import{_ as a,c as t,o,aj as r}from"./chunks/framework.guNMSiFm.js";const u=JSON.parse('{"title":"Network Deployment","description":"","frontmatter":{},"headers":[],"relativePath":"guide/best-practices/network-deployment.md","filePath":"guide/best-practices/network-deployment.md","lastUpdated":1777621302000}'),n={name:"guide/best-practices/network-deployment.md"};function i(s,e,l,d,c,p){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="network-deployment" tabindex="-1">Network Deployment <a class="header-anchor" href="#network-deployment" aria-label="Permalink to &quot;Network Deployment&quot;">​</a></h1><p>Treat an Iroha network as a coordinated system. Validators must agree on genesis, topology, trusted peers, and consensus-relevant configuration before the network can start and keep finalizing blocks.</p><h2 id="environment-separation" tabindex="-1">Environment Separation <a class="header-anchor" href="#environment-separation" aria-label="Permalink to &quot;Environment Separation&quot;">​</a></h2><ul><li>Maintain separate config bundles for local development, shared testnet, staging, and production.</li><li>Generate fresh keys for every non-disposable environment. Do not reuse localnet or Taira key material in production.</li><li>Keep peer config, client config, signed genesis, scripts, and deployment notes together as a versioned release artifact.</li><li>Store private keys outside repositories and deployment templates.</li></ul><p>See <a href="/iroha-2-docs/guide/configure/keys-for-network-deployment.html">Keys for Network Deployment</a>.</p><h2 id="genesis-and-topology" tabindex="-1">Genesis and Topology <a class="header-anchor" href="#genesis-and-topology" aria-label="Permalink to &quot;Genesis and Topology&quot;">​</a></h2><ul><li>Make every validator use the same signed genesis transaction, trusted peer set, topology, and validator Proofs-of-Possession when the profile requires them.</li><li>Use at least four validators for a minimum Byzantine-fault-tolerant deployment.</li><li>Separate validators from observers in capacity planning. Observers do not vote, propose, or collect, but they still consume storage, block sync, and network bandwidth.</li><li>Treat genesis, executor, and topology changes as coordinated migrations rather than single-peer edits.</li></ul><p>See <a href="/iroha-2-docs/reference/genesis.html">Genesis</a>, <a href="/iroha-2-docs/guide/configure/peer-management.html">Peer Management</a>, and <a href="/iroha-2-docs/guide/advanced/metrics.html#node-count-and-quorum">Performance and Metrics</a>.</p><h2 id="torii-and-network-access" tabindex="-1">Torii and Network Access <a class="header-anchor" href="#torii-and-network-access" aria-label="Permalink to &quot;Torii and Network Access&quot;">​</a></h2><ul><li>Put Torii behind a reverse proxy or firewall when it is exposed outside the host or private network.</li><li>Terminate TLS and apply basic authentication, rate limiting, and request-size controls at the edge when the deployment requires them.</li><li>Publish only the endpoints needed by the environment. Operator and telemetry routes should be more restricted than public read-only routes.</li><li>Bind listener addresses to host-local interfaces when peers should not accept remote traffic directly.</li></ul><p>See <a href="/iroha-2-docs/reference/torii-endpoints.html">Torii Endpoints</a> and <a href="/iroha-2-docs/guide/security/vpn.html">Virtual Private Networks</a>.</p><h2 id="consensus-and-capacity" tabindex="-1">Consensus and Capacity <a class="header-anchor" href="#consensus-and-capacity" aria-label="Permalink to &quot;Consensus and Capacity&quot;">​</a></h2><ul><li>Measure the deployment before tuning consensus timers. Lower timeouts can reduce latency only while network, storage, and execution layers keep up.</li><li>Watch queue direction, not just short samples of throughput. A queue that grows during steady load means the network is overloaded.</li><li>Record effective Sumeragi parameters, telemetry profile, validator count, network RTT, workload shape, and hardware details for each benchmark.</li><li>Increase collector fanout only after comparing latency, traffic, and backpressure signals.</li></ul><p>See <a href="/iroha-2-docs/guide/advanced/metrics.html">Performance and Metrics</a>.</p><h2 id="bare-metal-and-process-management" tabindex="-1">Bare-Metal and Process Management <a class="header-anchor" href="#bare-metal-and-process-management" aria-label="Permalink to &quot;Bare-Metal and Process Management&quot;">​</a></h2><ul><li>Keep each peer&#39;s <code>config.toml</code>, private key, storage directory, and ports separate.</li><li>Use process managers such as systemd with explicit restart, logging, and resource policies.</li><li>Preserve generated README and start commands from Kagami localnet bundles when translating a test topology to managed hosts.</li></ul><p>See <a href="/iroha-2-docs/guide/advanced/running-iroha-on-bare-metal.html">Running Iroha on Bare Metal</a>.</p>',17)])])}const m=a(n,[["render",i]]);export{u as __pageData,m as default};
